import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import { authService, studentService } from '../services/api';

const DEPTS = [
  'Computer Science & Engineering',
  'Electronics & Communication',
  'Mechanical Engineering',
  'Civil Engineering',
  'Electrical Engineering',
  'Information Technology',
  'Master of Computer Applications',
];

const BATCH_YEARS = Array.from({ length: 8 }, (_, i) => 2023 + i);

const INITIAL_REGISTER_FORM = {
  firstName: '',
  lastName: '',
  email: '',
  password: '',
  confirmPassword: '',
  rollNumber: '',
  department: '',
  batchYear: '',
  phone: '',
  gender: '',
  dateOfBirth: '',
  cgpa: '',
  skills: '',
  linkedinUrl: '',
  coverNote: '',
  resume: null,
};

const INITIAL_FORGOT_FORM = {
  email: '',
  newPassword: '',
  confirmPassword: '',
};

export default function LoginPage() {
  const [loading, setLoading] = useState(false);
  const [showForgotPassword, setShowForgotPassword] = useState(false);
  const [lf, setLf] = useState({ email: '', password: '' });
  const [rf, setRf] = useState(INITIAL_REGISTER_FORM);
  const [ff, setFf] = useState(INITIAL_FORGOT_FORM);
  const { login } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const isRegisterMode = location.pathname === '/register';

  const openLogin = () => navigate('/login');
  const openRegister = () => navigate('/register');

  const handleLogin = async event => {
    event.preventDefault();
    setLoading(true);

    try {
      const { data: loginData } = await authService.login(lf);
      login(loginData);

      toast.success(`Welcome back, ${loginData.firstName}!`);
      navigate(loginData.role === 'ADMIN' ? '/admin' : '/student');

      if (loginData.role === 'STUDENT') {
        studentService.getProfile()
          .then(({ data: profileData }) => {
            const fullUserData = { ...loginData, ...profileData };
            login(fullUserData);
          })
          .catch(error => {
            console.warn('Could not fetch student profile:', error);
          });
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Invalid credentials.');
      setLoading(false);
    }
  };

  const handleRegister = async event => {
    event.preventDefault();

    if (!rf.firstName.trim() || !rf.lastName.trim()) return toast.error('First and last name are required.');
    if (!/^[a-zA-Z\s]+$/.test(rf.firstName) || !/^[a-zA-Z\s]+$/.test(rf.lastName)) return toast.error('First and last name must contain characters only.');
    if (rf.password.length < 8) return toast.error('Password must be at least 8 characters.');
    if (rf.password !== rf.confirmPassword) return toast.error('Passwords do not match.');
    if (!rf.rollNumber.trim()) return toast.error('Roll number is required.');
    if (!/^[a-zA-Z0-9]+$/.test(rf.rollNumber)) return toast.error('Roll number must be alphanumeric.');
    if (!rf.batchYear.trim()) return toast.error('Batch year is required.');
    if (!rf.dateOfBirth.trim()) return toast.error('Date of birth is required.');

    const dobYear = parseInt(new Date(rf.dateOfBirth).getFullYear(), 10);
    if (dobYear >= 2010) return toast.error('Date of birth must be before 2010.');
    if (!rf.skills.trim()) return toast.error('Skills are required.');

    const skillsArr = rf.skills.split(',').map(skill => skill.trim()).filter(Boolean);
    if (skillsArr.length === 0) return toast.error('Please enter at least one skill.');
    if (!rf.email.endsWith('@students.git.edu')) return toast.error('Only @students.git.edu emails allowed.');
    if (!rf.department) return toast.error('Department is required.');

    setLoading(true);

    try {
      const formData = new FormData();
      const registerData = {
        firstName: rf.firstName,
        lastName: rf.lastName,
        email: rf.email,
        password: rf.password,
        rollNumber: rf.rollNumber,
        department: rf.department,
        batchYear: rf.batchYear,
        phone: rf.phone,
        gender: rf.gender,
        dateOfBirth: rf.dateOfBirth,
        cgpa: rf.cgpa,
        skills: rf.skills,
        linkedinUrl: rf.linkedinUrl,
        coverNote: rf.coverNote,
      };

      formData.append('registerData', new Blob([JSON.stringify(registerData)], { type: 'application/json' }));
      if (rf.resume) formData.append('resume', rf.resume);

      const { data } = await authService.registerWithFile(formData);
      toast.success(data.message);
      setRf(INITIAL_REGISTER_FORM);
      navigate('/pending');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Registration failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleForgotPassword = async event => {
    event.preventDefault();

    if (!ff.email.endsWith('@students.git.edu')) return toast.error('Use your student email address.');
    if (ff.newPassword.length < 8) return toast.error('New password must be at least 8 characters.');
    if (ff.newPassword !== ff.confirmPassword) return toast.error('Passwords do not match.');

    setLoading(true);

    try {
      const { data } = await authService.forgotPassword({
        email: ff.email,
        newPassword: ff.newPassword,
      });

      toast.success(data.message || 'Password updated successfully.');
      setShowForgotPassword(false);
      setFf(INITIAL_FORGOT_FORM);
      openLogin();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Could not update password.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-page">
      <div className={`login-card ${isRegisterMode ? 'register-mode' : ''}`}>
        {isRegisterMode && (
          <aside className="auth-showcase">
            <div className="auth-showcase-badge">Student onboarding</div>
            <h2>Create a placement-ready profile</h2>
            <p>
              Register once with your academic details, skills, and resume so the placement team can
              review and approve your account quickly.
            </p>

            <div className="auth-showcase-grid">
              <div className="auth-showcase-item">
                <strong>1</strong>
                <span>Enter your verified college and academic details</span>
              </div>
              <div className="auth-showcase-item">
                <strong>2</strong>
                <span>Upload your resume and highlight your core skills</span>
              </div>
              <div className="auth-showcase-item">
                <strong>3</strong>
                <span>Track approval and start applying to campus jobs</span>
              </div>
            </div>
          </aside>
        )}

        <div className="auth-panel">
          <div className="login-logo">
            <div className="login-logo-icon">
              <svg width="26" height="26" viewBox="0 0 24 24" fill="#c9a84c">
                <path d="M12 3L1 9l11 6 9-4.91V17h2V9L12 3zm-8.99 9.18L12 17l8.99-4.82.01 4.09-9 4.91-9-4.91.01-4.09z" />
              </svg>
            </div>
            <div>
              <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: 18, color: 'var(--navy)', marginBottom: 2 }}>
                GIT Placement Portal
              </h2>
              <p style={{ fontSize: 11, color: 'var(--gray-400)', letterSpacing: '0.5px' }}>
                CAMPUS RECRUITMENT SYSTEM
              </p>
            </div>
          </div>

          <div className="login-tabs">
            <button className={`login-tab${!isRegisterMode ? ' active' : ''}`} onClick={openLogin}>
              Sign In
            </button>
            <button className={`login-tab${isRegisterMode ? ' active' : ''}`} onClick={openRegister}>
              Register
            </button>
          </div>

          <div className="domain-badge">
            <div className="domain-dot" />
            {isRegisterMode ? '@students.git.edu only' : 'Admin or @students.git.edu'}
          </div>

          <div className="auth-heading">
            <h3>{isRegisterMode ? 'Student registration' : 'Welcome back'}</h3>
            <p>
              {isRegisterMode
                ? 'Complete your profile carefully so the placement office can approve it without delay.'
                : 'Sign in to manage placements, applications, and recruitment updates.'}
            </p>
          </div>

          {!isRegisterMode && (
            <form onSubmit={handleLogin}>
              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  placeholder="yourname@students.git.edu"
                  value={lf.email}
                  onChange={event => setLf(prev => ({ ...prev, email: event.target.value }))}
                  required
                />
              </div>
              <div className="form-group">
                <label>Password</label>
                <input
                  type="password"
                  placeholder="Enter your password"
                  value={lf.password}
                  onChange={event => setLf(prev => ({ ...prev, password: event.target.value }))}
                  required
                />
              </div>

              <button type="submit" className="btn btn-primary btn-full btn-lg" disabled={loading}>
                {loading ? 'Signing in...' : 'Sign In to Portal'}
              </button>

              <div className="auth-footer-link">
                <button type="button" className="btn-link" onClick={() => setShowForgotPassword(true)}>
                  Forgot password?
                </button>
              </div>
            </form>
          )}

          {isRegisterMode && (
            <form onSubmit={handleRegister}>
              <div className="form-row">
                <div className="form-group">
                  <label>First Name *</label>
                  <input type="text" required value={rf.firstName} onChange={event => setRf(prev => ({ ...prev, firstName: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Last Name *</label>
                  <input type="text" required value={rf.lastName} onChange={event => setRf(prev => ({ ...prev, lastName: event.target.value }))} />
                </div>
              </div>

              <div className="form-group">
                <label>College Email *</label>
                <input type="email" required value={rf.email} onChange={event => setRf(prev => ({ ...prev, email: event.target.value }))} />
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Password *</label>
                  <input type="password" required value={rf.password} onChange={event => setRf(prev => ({ ...prev, password: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Confirm Password *</label>
                  <input type="password" required value={rf.confirmPassword} onChange={event => setRf(prev => ({ ...prev, confirmPassword: event.target.value }))} />
                </div>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Roll Number *</label>
                  <input type="text" required value={rf.rollNumber} onChange={event => setRf(prev => ({ ...prev, rollNumber: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Batch Year *</label>
                  <select required value={rf.batchYear} onChange={event => setRf(prev => ({ ...prev, batchYear: event.target.value }))}>
                    <option value="">Select batch year</option>
                    {BATCH_YEARS.map(year => <option key={year}>{year}</option>)}
                  </select>
                </div>
              </div>

              <div className="form-group">
                <label>Department *</label>
                <select required value={rf.department} onChange={event => setRf(prev => ({ ...prev, department: event.target.value }))}>
                  <option value="">Select department</option>
                  {DEPTS.map(department => <option key={department}>{department}</option>)}
                </select>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Phone</label>
                  <input type="text" value={rf.phone} onChange={event => setRf(prev => ({ ...prev, phone: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Gender</label>
                  <select value={rf.gender} onChange={event => setRf(prev => ({ ...prev, gender: event.target.value }))}>
                    <option value="">Select</option>
                    <option>Male</option>
                    <option>Female</option>
                    <option>Other</option>
                  </select>
                </div>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Date of Birth *</label>
                  <input type="date" required value={rf.dateOfBirth} onChange={event => setRf(prev => ({ ...prev, dateOfBirth: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>CGPA</label>
                  <input type="text" value={rf.cgpa} onChange={event => setRf(prev => ({ ...prev, cgpa: event.target.value }))} />
                </div>
              </div>

              <div className="form-group">
                <label>Skills * (comma separated)</label>
                <input type="text" required value={rf.skills} onChange={event => setRf(prev => ({ ...prev, skills: event.target.value }))} />
              </div>

              <div className="form-group">
                <label>LinkedIn URL</label>
                <input type="text" value={rf.linkedinUrl} onChange={event => setRf(prev => ({ ...prev, linkedinUrl: event.target.value }))} />
              </div>

              <div className="form-group">
                <label>Cover Note</label>
                <textarea rows={3} value={rf.coverNote} onChange={event => setRf(prev => ({ ...prev, coverNote: event.target.value }))} />
              </div>

              <div className="form-group">
                <label>Resume (Optional - PDF/DOCX, max 5MB)</label>
                <input type="file" accept=".pdf,.docx" onChange={event => setRf(prev => ({ ...prev, resume: event.target.files?.[0] || null }))} />
                {rf.resume && (
                  <div className="file-badge">
                    <strong>Attached</strong>
                    <span>{rf.resume.name}</span>
                  </div>
                )}
              </div>

              <button type="submit" className="btn btn-gold btn-full btn-lg" disabled={loading}>
                {loading ? 'Submitting...' : 'Submit for Approval'}
              </button>

              <p className="auth-inline-note">
                Already registered? <button type="button" className="btn-link" onClick={openLogin}>Sign in</button>
              </p>
            </form>
          )}
        </div>
      </div>

      {showForgotPassword && (
        <div className="modal-overlay" onClick={() => setShowForgotPassword(false)}>
          <div className="modal auth-modal" onClick={event => event.stopPropagation()}>
            <button type="button" className="modal-close" onClick={() => setShowForgotPassword(false)}>
              x
            </button>
            <div className="auth-heading" style={{ marginBottom: 20 }}>
              <h3>Reset password</h3>
              <p>Enter your existing student email and set a new password for your account.</p>
            </div>

            <form onSubmit={handleForgotPassword}>
              <div className="form-group">
                <label>Existing Email</label>
                <input type="email" required value={ff.email} onChange={event => setFf(prev => ({ ...prev, email: event.target.value }))} />
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>New Password</label>
                  <input type="password" required value={ff.newPassword} onChange={event => setFf(prev => ({ ...prev, newPassword: event.target.value }))} />
                </div>
                <div className="form-group">
                  <label>Confirm Password</label>
                  <input type="password" required value={ff.confirmPassword} onChange={event => setFf(prev => ({ ...prev, confirmPassword: event.target.value }))} />
                </div>
              </div>

              <div className="btn-row" style={{ justifyContent: 'space-between' }}>
                <button type="button" className="btn btn-outline" onClick={() => setShowForgotPassword(false)}>
                  Cancel
                </button>
                <button type="submit" className="btn btn-primary" disabled={loading}>
                  {loading ? 'Updating...' : 'Update Password'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
